xpath.script:
window.dataLayer = window.dataLayer || [];
function gtag(){dataLayer.push(arguments);}
gtag('consent', 'default', {
    'ad_storage': 'denied',
    'ad_user_data': 'denied',
    'ad_personalization': 'denied',
    'analytics_storage': 'denied',
    'functionality_storage': 'granted',
    'security_storage': 'granted',
    'wait_for_update': 500
});
gtag('set', 'ads_data_redaction', true);
gtag('set', 'url_passthrough', true);

gtag('js', new Date());
gtag('config', 'G-CJTPLY088E', {
    'anonymize_ip': true,
    'transport_type': 'beacon'
});
(function () {
    // Schedule gtag.js to load after window.load so it never
    // blocks LCP/TBT, but before the user can navigate away —
    // critical for click-through events on anchor links where
    // lazy-on-interaction would race with navigation.
    var loaded = false;
    function load() {
        if (loaded) return;
        loaded = true;
        var s = document.createElement('script');
        s.async = true;
        s.src = 'https://www.googletagmanager.com/gtag/js?id=G-CJTPLY088E';
        document.head.appendChild(s);
    }
    function schedule() {
        if ('requestIdleCallback' in window) {
            requestIdleCallback(load, { timeout: 2000 });
        } else {
            setTimeout(load, 1500);
        }
    }
    if (document.readyState === 'complete') {
        schedule();
    } else {
        window.addEventListener('load', schedule, { once: true });
    }
})();
